const PRODUCTS = [
  { id: 1, name: 'Laptop Pro',      price: 1299, inventory: 42, category: 'Electronics' },
  { id: 2, name: 'Wireless Phone',  price:  799, inventory: 88, category: 'Electronics' },
  { id: 3, name: 'Tablet Air',      price:  549, inventory: 35, category: 'Electronics' },
  { id: 4, name: 'Noise-Cancel Headphones', price: 249, inventory: 120, category: 'Audio'    },
  { id: 5, name: 'Smart Watch',     price:  349, inventory: 67, category: 'Wearables' },
  { id: 6, name: 'Bluetooth Speaker', price:  129, inventory: 94, category: 'Audio'    },
  { id: 7, name: 'USB-C Hub',       price:   59, inventory: 200, category: 'Accessories' },
  { id: 8, name: 'Mechanical Keyboard', price: 179, inventory: 53, category: 'Accessories' },
];

/** Last time the upstream ERP/PIM was polled for changes. */
let lastSyncedAt = '2026-07-01T00:00:00.000Z';

/** Simple counter bumped each sync so we can visually verify changes. */
let syncGeneration = 0;

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Retrieve the current product catalog snapshot.
 * Simulates a ~100 ms database read.
 */
export async function getAllProducts() {
  await new Promise((resolve) => setTimeout(resolve, 100));

  return {
    products: PRODUCTS.map((p) => ({ ...p })),
    syncedAt: lastSyncedAt,
    generation: syncGeneration,
  };
}

/**
 * Trigger a full upstream sync (ERP / PIM).
 *
 * Simulates a slow network payload — pricing, inventory, and availability
 * coming in from the upstream system.  In production this would batch-update
 * thousands of SKUs.
 */
export async function syncCatalog() {
  // Simulate the latency of a real ERP integration
  await new Promise((resolve) => setTimeout(resolve, 3_000));

  // ---- upstream data arrives ----
  // Bump generation so the UI can detect that *something* changed
  syncGeneration += 1;

  // Perturb prices slightly to mimic real changes trickling in
  for (const product of PRODUCTS) {
    const delta = Math.round((Math.random() - 0.5) * 40);
    product.price = Math.max(1, product.price + delta);
    product.inventory = Math.max(
      0,
      product.inventory + Math.round((Math.random() - 0.5) * 20)
    );
  }

  lastSyncedAt = new Date().toISOString();

  return { synced: true, timestamp: lastSyncedAt };
}


