import { unstable_cache } from 'next/cache';

import { getAllProducts } from './db';

export interface Product {
  id: number;
  name: string;
  price: number;
  inventory: number;
  category: string;
}

export interface CatalogSnapshot {
  products: Product[];
  syncedAt: string;
  generation: number;
}

/**
 * Cached catalog reader.
 *
 * Uses the cache tag `"products"` so that any Server Action or route handler
 * can invalidate this value by calling `revalidateTag("products")`.  All views
 * that depend on the same catalog data share this single cache entry and will
 * be refreshed together on next access after invalidation.
 */
export const getCachedProducts = unstable_cache(
  async (): Promise<CatalogSnapshot> => {
    console.log('[products] cache MISS — fetching catalog from DB');
    return getAllProducts();
  },
  // Stable key parts — changing these would create a new cache slot
  ['products-catalog-data'],
  {
    // ── MUST match the tag used by the sync action ──
    tags: ['products'],
  },
);

